head.script:
/**
 * 화 면 명 : 임대차[전대차] 담보평가
 * 메뉴경로 : 공통/총무업무/임대차관리/임대차[전대차] 계약관리/임대차[전대차] 계약기본정보
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/cm/bc/rentloan/zz_900_01_03b.jsp
 * 작 성 자 : 정승혜
 * 작 업 일 : 2025-11-14
 * 수정이력  :
 *    - 2025-11-14      정승혜    최초작성
 *    - 2025-12-23      정승혜    pub 경로 -> ui로 변경 / f_winOpen수정
 *    - 2025-12-24      정승혜    popTitleCh 적용
 *    - 2026-01-12      정승혜    기타수정
 *    - 2026-01-19      정승혜    submitdone 조건수정
 * 메모 : 
 * gr_List1,gr_List2 Disable 시 이동처리가 안되어 빼고 isStarted 구분값으로 조건처리함
 * 삭제시 delete 처리해서 getModifiedIndex 에 처리되지 않아서 list2CountFlag 구분값으로 조건처리
 * 조회조건: A20260106001
 * 
 */

//hidden
scwin.txt_rentloanNo = "";
scwin.txt_rentloanSeq = "";
scwin.hid_uppermostBizDomCd = "";
scwin.hid_seq = "";
scwin.hid_cardNo = "";

scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");

scwin.strBasSdId = "/ui/cm/bc/rentloan/zz_900_01_01b.xml";
scwin.strCtrtBaseSdId = "/ui/cm/bc/rentloan/zz_900_01_02b.xml";

scwin.params = "";

scwin.rentloanNo = "";
scwin.rentloanSeq = "";
scwin.mode = "";
scwin.eqSelBizDom = "";
scwin.cfValue = "";
scwin.popYn = "";

scwin.memJson = "";
scwin.regId = "";
scwin.sysAdminYn = "";

//////////////////////////////    
scwin.uppermostBizDomCd = ""; //최상위사업영역
scwin.selBizDom = scwin.eqSelBizDom;

//////////////////////////////    
scwin.sRentloanNo = "";
scwin.sRentloanSeq = "";
scwin.sMode = "";
scwin.user = "";

scwin.sPldgClsCd = "00"; 

//////////////////////////////    
scwin.flag = 0;
scwin.position1 = "";

scwin.isStarted = false;
scwin.list2CountFlag = false; 

    //-------------------------------------------------------------------------
    // function name : f_OnLoad
    // function desc : 화면로딩시
    // function Parameter : null 
    //-------------------------------------------------------------------------
scwin.onpageload = function() {
    console.log("zz_900_01_03b_pgmId : "+$c.data.getParameter($p, "menuInfo").pgmId)

    scwin.memJson = $c.data.getMemInfo();
    scwin.regId = scwin.memJson.userId;
    scwin.sysAdminYn = scwin.memJson.sysAdminYn;	

    const codeOptions = [
    { grpCd : "ZZ914", compID : "gr_List1:pldgClsCd, gr_List2:pldgClsCd, lc_pldgClsCd" },
    { grpCd : "ZZ915", compID : "gr_List1:othrPldgCd, lc_othrPldgCd" },
    { grpCd : "ZZ916", compID : "gr_List1:posnClsCd, lc_posnClsCd" },
    { grpCd : "ZZ910", compID : "lc_rentloanClsCd" },
    { grpCd : "ZZ911", compID : "lc_rentloanShapeCd" },
    ];
    $c.data.setCommonCode(codeOptions);

    scwin.params = $c.data.getParameter();
    if(scwin.params["rentloanNo"] == null){scwin.rentloanNo = "";}else{scwin.rentloanNo = scwin.params["rentloanNo"]} //계약번호
    if(scwin.params["rentloanSeq"] == null){scwin.rentloanSeq = "";}else{scwin.rentloanSeq = scwin.params["rentloanSeq"]} //계약순번
    if(scwin.params["mode"] == null){scwin.mode = "";}else{scwin.mode = scwin.params["mode"]} //NEW, CHG, REN, MOD, DEL, ''
    if(scwin.params["selBizDom"] == null){scwin.eqSelBizDom = "";}else{scwin.eqSelBizDom = scwin.params["selBizDom"]}
    if(scwin.params["cf"] == null){scwin.cfValue = "";}else{scwin.cfValue = scwin.params["cf"]}
    if(scwin.params["popYn"] == null){scwin.popYn = "";}else{scwin.popYn = scwin.params["popYn"]}
    scwin.sRentloanNo = scwin.params["rentloanNo"];
    scwin.sRentloanSeq = scwin.params["rentloanSeq"];
    scwin.sMode = scwin.params["sMode"];
    scwin.user = scwin.params["regId"];
};

scwin.ondataload = function() {
    dlt_commonCodeZZ914.sort("cd", 0);
    dlt_commonCodeZZ915.sort("cd", 0);
    //DataList에 추가할 데이터 정의
    let tmpData = [{"grpCd":"ZZ914","cd":"00","cdNm":"없음","sortSeq":"0"}];
    //dlt_commonCodeZZ914.insertJSON( 0, tmpData ); // 두번들어가서 수정함
    dlt_commonCodeZZ914.insertRow(0);
    dlt_commonCodeZZ914.setCellData(0,"grpCd","ZZ914");
    dlt_commonCodeZZ914.setCellData(0,"cd","00");
    dlt_commonCodeZZ914.setCellData(0,"cdNm","없음");
    dlt_commonCodeZZ914.setCellData(0,"sortSeq","0");

    //로그인한 사번으로 최상위사업영역을 가져오는 데이타셋 실행
    scwin.f_uppermostBizdom();

    scwin.f_HeaderCreate();   //데이터셋 헤더생성
    scwin.f_FieldClear();
    scwin.f_RetrieveRentloan();	// 계약내역 조회

    $c.util.setTimeout(function() {
        $c.gus.cfDisableObjects([ed_rentloanStDt, ed_rentloanEndDt, ed_closeDt, ed_addr1]);
    }, {"delay":200});  


	scwin.hid_uppermostBizDomCd = scwin.uppermostBizDomCd;	

    if(scwin.popYn == 'Y')	// 팝업으로 넘어오는 항목인 경우 목록 버튼 비활성화
    {
        $c.gus.cfDisableObjects([btn_save, btn_list, ed_addr1]);
    }
};

scwin.popTitleCh = function() {
    $c.data.setPopupTitle("임대차[전대차] 담보평가");
};

    //-------------------------------------------------------------------------
