    }
};

    //-------------------------------------------------------------------------
    // function name : f_PldgClsCdChange
    // function desc : 담보구분 변경 시
    // function Parameter : null 
    //-------------------------------------------------------------------------
scwin.f_PldgClsCdChange = function(info) {
    if(ds_List1.getRowPosition() == null){
        ds_List1.setRowPosition(0);
    }
    let rentloanNo = ds_List1.getCellData(ds_List1.getRowPosition(), "rentloanNo");
    let rentloanSeq = ds_List1.getCellData(ds_List1.getRowPosition(), "rentloanSeq");
    let pldgSeq = ds_List1.getCellData(ds_List1.getRowPosition(), "pldgSeq");
    let vSearchClsCd = ds_List1.getCellData(ds_List1.getRowPosition(), "pldgClsCd");
    scwin.sPldgClsCd = vSearchClsCd;

    $c.gus.cfDisableObjects([oPldgInfo, btn_add1, btn_del1, btn_cls1, btn_add2, btn_del2, btn_cls2, ed_addr1]); //gr_List1 gr_List2
    if ( vSearchClsCd == "00" ) {
        ds_List1.removeAll();
        scwin.flag = 1;
        scwin.f_Reset();
        ds_List1.setCellData(ds_List1.getRowPosition(), "pldgClsCd", vSearchClsCd);
        ds_List1.setCellData(ds_List1.getRowPosition(), "setupDt", "");	// 설정일자
        ds_List1.setCellData(ds_List1.getRowPosition(), "buildYy", "");	// 준공년도
        ds_List2.removeAll();
        $c.gus.cfDisableObjects([oPldgInfo, btn_add1, btn_del1, btn_cls1, btn_add2, btn_del2, btn_cls2, ed_addr1]); //gr_List1 gr_List2
        $c.gus.cfEnableObjects([lc_pldgClsCd]);

    //부동산담보(토지)
    } else if ( vSearchClsCd == "01" ) {
        scwin.isStarted = true;
        $c.gus.cfInitObjects([ed_roolNum, ed_estmtBasis]);
        $c.gus.cfEnableObjects([oPldgInfo, btn_add1, btn_del1, btn_cls1, btn_add2, btn_del2, btn_cls2]); //gr_List1 gr_List2
        $c.gus.cfDisableObjects([ed_mergeRentloanNo, ed_clntNo, ed_clntNm, lc_rentloanClsCd, lc_rentloanShapeCd, ed_addr1, ed_roolNum, ed_estmtBasis, ed_addr1]);

    //부동산담보(건물), 부동산담보(토지/건물공동) 
    } else if ( vSearchClsCd == "02" || vSearchClsCd == "05") {
        scwin.isStarted = true;
        $c.gus.cfInitObjects([ed_ancdLpr]);
        ds_List1.modifyRowStatus(ds_List1.getRowPosition(), "R");
        $c.gus.cfEnableObjects([oPldgInfo, btn_add1, btn_del1, btn_cls1, btn_add2, btn_del2, btn_cls2]); //gr_List2, gr_List1
        $c.gus.cfDisableObjects([ed_mergeRentloanNo, ed_clntNo, ed_clntNm, lc_rentloanClsCd, lc_rentloanShapeCd, ed_addr1, ed_ancdLpr, ed_addr1]);

    //그 외
    } else {
        scwin.isStarted = true;
        $c.gus.cfInitObjects([ed_lotNo, ed_roolNum, ed_regAreaM2, ed_regAreaPy, ed_ancdLpr, ed_estmtAmt, ed_estmtBasis]);
        $c.gus.cfEnableObjects([oPldgInfo, btn_add1, btn_del1, btn_cls1]); //gr_List1
        $c.gus.cfDisableObjects([ed_mergeRentloanNo, ed_clntNo, ed_clntNm, lc_rentloanClsCd, lc_rentloanShapeCd, ed_addr1, ed_lotNo, ed_roolNum, ed_regAreaM2, ed_regAreaPy, ed_ancdLpr, ed_estmtAmt, ed_estmtBasis, ed_addr1]); //gr_List2
        scwin.f_deleteDetail(rentloanNo, rentloanSeq, pldgSeq);
    }
    scwin.flag = 0;
};

scwin.lc_pldgClsCd_onchange = async function (info) {
    if(scwin.flag==0) {	
        if (ds_List1.getCellData(ds_List1.getRowPosition(), "pldgClsCd") == "00") {
            let confirm = await $c.win.confirm("담보구분 '없음' 선택 시 데이터가 삭제됩니다. 변경하시겠습니까?")
            if( !confirm ) {
                lc_pldgClsCd.setValue(scwin.sPldgClsCd);
                return;
            }
        }
        scwin.f_PldgClsCdChange();
    }	      
};


scwin.f_deleteDetail = function(rentloanNo, rentloanSeq, pldgSeq) {
    for(let i= ds_List2.getRowCount(); i>=0 ;i--){
        if(ds_List2.getCellData(i, "rentloanNo") == rentloanNo
                && ds_List2.getCellData(i, "rentloanSeq") == rentloanSeq
                && ds_List2.getCellData(i, "pldgSeq") == pldgSeq) {
            ds_List2.removeRow(i);
        }
    }
};

